"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["7719"],{95461(a,e,n){n.r(e),n.d(e,{default:()=>r});var i=n(74848),t=n(47643),s=JSON.parse('{"id":270,"ind":{"title":"Ahli Pertanyaan Pro","prompt":"You are an expert in management, anthropology, sociology, psychology, philosophy, linguistics, cultural commentary, and psychoanalytic theory.\\n\\nFor the next part, I will give you a \\"Question X\\". Instead of answering it directly, analyze the question as follows:\\n\\n1. Assess \\"Question X\\" for quality, giving five reasons.\\n2. Improve \\"Question X\\", presenting five new versions.\\n3. Devise an answer to \\"Question X\\", detailing your thought process.\\n4. Guess why \\"Question X\\" was asked, suggesting five possible motives.\\n5. Identify five areas of knowledge the questioner might be lacking.\\n6. Infer five potential assumptions of the questioner.\\n7. Discuss these assumptions, outlining their pros, cons and impact on the questioner.\\n8. Speculate on the questioner\'s worldview and values, listing five key points.\\n9. Critique the inferred worldview and values, discussing their pros, cons and influence on the questioner.\\n10. Hypothesize about the questioner\'s self-identity.\\n11. Evaluate this self-identity, discussing its strengths, weaknesses, and impact on the questioner. Respond in Indonesian. Question X: [pertanyaan pertama untuk diperdalam]","description":"Analisis, perbaiki, dan jawab pertanyaan dari berbagai sudut pandang ahli (manajemen, psikologi, filsafat...).","remark":"Analisis mendalam tentang pertanyaan dan penanya dari berbagai aspek akademis. Disumbangkan oleh @\u81EA\u7531\u53F6."},"tags":["contribute","mind"],"website":null,"count":1308,"related":[{"id":206,"title":"Asisten Berpikir Mendalam","remark":"Berikan pertanyaan berkualitas tinggi dan berharga berdasarkan kata kunci, tema, atau konsep, yang mencakup berbagai aspek kognisi, emosi, dan perilaku manusia, untuk melatih kemampuan berpikir mendalam seseorang. Struktur respons prompt ini sangat jelas, sehingga cocok digunakan saat mengatur konsep. Dikontribusikan oleh @MoeACG."},{"id":196,"title":"Lembaga Pemikir","remark":"Memberi Anda berbagai perspektif berbeda untuk berpikir. Dikontribusikan oleh @jiuwen624."},{"id":176,"title":"Asisten Pertanyaan","remark":"Tanyakan dari berbagai sudut untuk memicu pemikiran mendalam. Dikontribusikan oleh @meishiwanwan."}],"metaTitle":"Cloud Migration: Migrasi Cloud","metaDescription":"Migrasi ke cloud? Strategi untuk cloud migration!","faq":[{"q":"Apa bedanya dengan ID 176 asisten pertanyaan?","a":"ID 176 hanya generate pertanyaan; ID 270 pertama menilai kualitas pertanyaan, lalu menambah premis, lalu kasih analisis multi-perspektif \u2014 strukturnya lebih lengkap. Untuk pembedahan mendalam sekali jalan pakai 270; buat brainstorming cepat pakai 176. Topik riset disarankan 270 buat eksplorasi awal."},{"q":"Apakah perspektif disiplin (manajemen/antropologi/dll.) yang dipakai AI benar-benar mendalam?","a":"Untuk disiplin yang familiar ke publik (psikologi, sosiologi) bisa kasih analisis yang cukup mendalam; untuk disiplin niche (kritik budaya, psikoanalisis) mudah sekadar menempelkan label. Untuk analisis kunci, tanyakan \'peneliti mana di disiplin itu yang pandangannya paling relevan\' \u2014 cara cepat untuk membedakan apakah AI benar-benar paham."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,i.jsx)(t.A,{prompt:s,currentLanguage:"ind"})}}}]);